Anthropic.Completions = Completions;
Anthropic.Messages = Messages2;
Anthropic.Models = Models2;
Anthropic.Beta = Beta;
// src/agent/anthropic-api.ts
var client = null;
function getClient(config) {
  if (!client) {
    client = new Anthropic({ apiKey: config.apiKey });
  }
  return client;
}
async function callAnthropicAPI(systemPrompt, userMessage, config) {
  console.log(`Calling Anthropic API: ${userMessage.substring(0, 50)}...`);
  try {
    const anthropic = getClient(config);
    const response = await anthropic.messages.create({
      model: config.model,
      max_tokens: config.maxTokens,
      system: systemPrompt,
      messages: [{ role: "user", content: userMessage }]
    });
    const block = response.content[0];
    if (block.type === "text") {
      return block.text.trim();
    }
    return "Error: Unexpected response format from Anthropic API";
  } catch (error2) {
    console.error("Anthropic API error:", error2.message || error2);
    return `Error: ${error2.message || "Anthropic API call failed"}`;
  }
}

// src/scheduler/telegram.ts
var MAX_LENGTH = 4000;
async function sendTelegram(botToken, chatId, message, parseMode) {
  const chunks = splitMessage(message);
  for (const chunk of chunks) {
    const body = { chat_id: chatId, text: chunk };
    if (parseMode)
      body.parse_mode = parseMode;
    try {
      const response = await fetch(`https://api.telegram.org/bot${botToken}/sendMessage`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body)
      });
      if (!response.ok) {
        const err = await response.text();
        console.error("Telegram send failed:", err);
        return false;
      }
    } catch (error2) {
      console.error("Telegram send error:", error2);
      return false;
    }
  }
  return true;
}
function splitMessage(text) {
  if (text.length <= MAX_LENGTH)
    return [text];
  const chunks = [];
  let remaining = text;
  while (remaining.length > 0) {
    if (remaining.length <= MAX_LENGTH) {
      chunks.push(remaining);
      break;
    }
    let splitIndex = remaining.lastIndexOf(`

`, MAX_LENGTH);
    if (splitIndex === -1)
      splitIndex = remaining.lastIndexOf(`
`, MAX_LENGTH);
    if (splitIndex === -1)
      splitIndex = remaining.lastIndexOf(" ", MAX_LENGTH);
    if (splitIndex === -1)
      splitIndex = MAX_LENGTH;
    chunks.push(remaining.substring(0, splitIndex));
    remaining = remaining.substring(splitIndex).trim();
  }
  return chunks;
}

// src/scheduler/context.ts
async function createSchedulerContext() {
  const config = loadConfig();
  if (!config.anthropic) {
    console.error("Scheduler requires ANTHROPIC_API_KEY");
    process.exit(1);
  }
  if (!config.supabase) {
    console.error("Scheduler requires Supabase configuration");
    process.exit(1);
  }
  const memory = createMemory(config.supabase);
  const profile = await loadProfile(config.paths.projectRoot);
  const chatId = config.telegram.allowedUserIds[0];
  if (!chatId) {
    console.error("No TELEGRAM_USER_ID configured");
    process.exit(1);
  }
  return {
    config,
    memory,
    profile,
    sendTelegram: (message, parseMode) => sendTelegram(config.telegram.botToken, chatId, message, parseMode),
    callClaude: (systemPrompt, userMessage) => callAnthropicAPI(systemPrompt, userMessage, config.anthropic)
  };
}

// src/scheduler/data.ts
var WEATHER_CODES = {
  0: "Clear sky",
  1: "Mainly clear",
  2: "Partly cloudy",
  3: "Overcast",
  45: "Foggy",
  48: "Rime fog",
  51: "Light drizzle",
  53: "Moderate drizzle",
  55: "Dense drizzle",
  56: "Freezing drizzle",
  57: "Heavy freezing drizzle",
  61: "Slight rain",
  63: "Moderate rain",
  65: "Heavy rain",
  66: "Freezing rain",
  67: "Heavy freezing rain",
  71: "Slight snow",
  73: "Moderate snow",
  75: "Heavy snow",
  77: "Snow grains",
  80: "Slight showers",
  81: "Moderate showers",
  82: "Violent showers",
  85: "Slight snow showers",
  86: "Heavy snow showers",
  95: "Thunderstorm",
  96: "Thunderstorm with hail",
  99: "Thunderstorm with heavy hail"
};
async function fetchWeather(latitude, longitude, timezone) {
  try {
    const url = new URL("https://api.open-meteo.com/v1/forecast");
    url.searchParams.set("latitude", latitude.toString());
    url.searchParams.set("longitude", longitude.toString());
    url.searchParams.set("current", "temperature_2m,apparent_temperature,weather_code,relative_humidity_2m,wind_speed_10m");
    url.searchParams.set("daily", "temperature_2m_max,temperature_2m_min,precipitation_probability_max");
    url.searchParams.set("temperature_unit", "fahrenheit");
    url.searchParams.set("wind_speed_unit", "mph");
    url.searchParams.set("timezone", timezone);
    url.searchParams.set("forecast_days", "1");
    const response = await fetch(url.toString());
    if (!response.ok)
      return null;
    const data = await response.json();
    const current = data.current;
    const daily = data.daily;
    return {
      temperature: Math.round(current.temperature_2m),
      apparentTemperature: Math.round(current.apparent_temperature),
      weatherCode: current.weather_code,
      weatherDescription: WEATHER_CODES[current.weather_code] || "Unknown",
      high: Math.round(daily.temperature_2m_max[0]),
      low: Math.round(daily.temperature_2m_min[0]),
      precipitationProbability: daily.precipitation_probability_max[0] || 0,
      humidity: current.relative_humidity_2m,
      windSpeed: Math.round(current.wind_speed_10m)
    };
  } catch (error2) {
    console.error("Weather fetch failed:", error2);
    return null;
  }
}
async function fetchNews(tavilyApiKey, topic = "AI and technology") {
  try {
    const response = await fetch("https://api.tavily.com/search", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        api_key: tavilyApiKey,
        query: `${topic} news today`,
        max_results: 5,
        search_depth: "basic",
        include_answer: false
      })
    });
    if (!response.ok)
      return [];
    const data = await response.json();
    return (data.results || []).map((r) => ({
      title: r.title || "Untitled",
      url: r.url || "",
      snippet: r.content?.substring(0, 200) || ""
    }));
  } catch (error2) {
    console.error("News fetch failed:", error2);
    return [];
  }
}
async function fetchGoals(client2) {
  try {
    const { data } = await client2.rpc("get_active_goals");
    return (data || []).map((g) => ({
      content: g.content,
      deadline: g.deadline ? new Date(g.deadline).toLocaleDateString() : undefined
    }));
  } catch (error2) {
    console.error("Goals fetch failed:", error2);
    return [];
  }
}
async function fetchFacts(client2) {
  try {
    const { data } = await client2.rpc("get_facts");
    return (data || []).map((f) => f.content);
  } catch (error2) {
    console.error("Facts fetch failed:", error2);
    return [];
  }
}
async function fetchTaskSummary(client2) {
  try {
    const todayStart = new Date;
    todayStart.setHours(0, 0, 0, 0);
    const [activeResult, completedResult] = await Promise.all([
      client2.from("tasks").select("description, status").in("status", ["pending", "running"]),
      client2.from("tasks").select("description").eq("status", "completed").gte("updated_at", todayStart.toISOString())
    ]);
    return {
      activeTasks: (activeResult.data || []).map((t) => ({
        description: t.description,
        status: t.status
      })),
      completedToday: (completedResult.data || []).map((t) => ({
        description: t.description
      }))
    };
  } catch (error2) {
    console.error("Tasks fetch failed:", error2);
    return { activeTasks: [], completedToday: [] };
  }
}

// src/scheduler/briefing.ts
async function assembleBriefingData(ctx) {
  const { config, memory } = ctx;
  const client2 = memory.client;
  const [weather, goals, tasks, facts, news] = await Promise.allSettled([
    config.location ? fetchWeather(config.location.latitude, config.location.longitude, config.user.timezone) : Promise.resolve(null),
    fetchGoals(client2),
    fetchTaskSummary(client2),
    fetchFacts(client2),
    config.tasks.tavilyApiKey ? fetchNews(config.tasks.tavilyApiKey, "AI and technology") : Promise.resolve([])
  ]);
  const sections = [];
  const now = new Date;
  const dateStr = now.toLocaleDateString("en-US", {
    timeZone: config.user.timezone,
    weekday: "long",
    month: "long",
    day: "numeric"
  });
  sections.push(`Date: ${dateStr}`);
  const weatherData = weather.status === "fulfilled" ? weather.value : null;
  if (weatherData) {
    const cityLabel = config.location?.cityName ? ` in ${config.location.cityName}` : "";
    sections.push(`Weather${cityLabel}: ${weatherData.weatherDescription}, ${weatherData.temperature}\xB0F ` + `(feels like ${weatherData.apparentTemperature}\xB0F). ` + `High ${weatherData.high}\xB0F, Low ${weatherData.low}\xB0F. ` + `${weatherData.precipitationProbability}% chance of precipitation. ` + `Wind ${weatherData.windSpeed} mph.`);
  }
  const goalsData = goals.status === "fulfilled" ? goals.value : [];
  if (goalsData.length) {
    sections.push(`Active Goals:
` + goalsData.map((g) => `- ${g.content}${g.deadline ? ` (by ${g.deadline})` : ""}`).join(`
`));
  }
  const tasksData = tasks.status === "fulfilled" ? tasks.value : { activeTasks: [], completedToday: [] };
  if (tasksData.completedToday.length) {
    sections.push(`Recently Completed:
` + tasksData.completedToday.map((t) => `- ${t.description}`).join(`
`));
  }
  if (tasksData.activeTasks.length) {
    sections.push(`In Progress:
` + tasksData.activeTasks.map((t) => `- ${t.description}`).join(`
`));
  }
  const newsData = news.status === "fulfilled" ? news.value : [];
  if (newsData.length) {
    sections.push(`AI/Tech News:
` + newsData.map((n) => `- ${n.title}`).join(`
`));
  }
  const factsData = facts.status === "fulfilled" ? facts.value : [];
  if (factsData.length) {
    sections.push(`User context:
` + factsData.slice(0, 10).map((f) => `- ${f}`).join(`
`));
  }
  return sections.join(`

`);
}
async function main() {
  console.log("Building morning briefing...");
  const ctx = await createSchedulerContext();
  const { config, memory } = ctx;
  const rawData = await assembleBriefingData(ctx);
  console.log("Data assembled. Synthesizing with Claude...");
  const systemPrompt = `You are Bright, sending a morning briefing to ${config.user.name} on Telegram.

${ctx.profile ? `User profile:
${ctx.profile}
` : ""}
Write a concise, friendly morning briefing based on the data below. Guidelines:
- Start with a brief greeting appropriate for the day/weather.
- Keep each section to 2-3 lines maximum.
- Highlight anything time-sensitive or particularly relevant to the user's goals.
- If there's no data for a section, skip it entirely \u2014 don't mention missing data.
- End with one brief, encouraging or actionable sentence.
- Total length: aim for 15-25 lines. Concise and scannable.
- Do NOT use markdown headers (#). Use simple text with line breaks.
- You can use bold (*text*) sparingly for section labels.`;
  const userMessage = `Here is today's data to synthesize into a morning briefing:

${rawData}`;
  const briefing = await ctx.callClaude(systemPrompt, userMessage);
  console.log("Sending briefing...");
  const sent = await ctx.sendTelegram(briefing);
  if (sent) {
    console.log("Briefing sent!");
    await memory.saveMessage("assistant", briefing, {
      source: "briefing"
    });
  } else {
    console.error("Failed to send briefing");
    process.exit(1);
  }
  if (memory.client) {
    await memory.client.from("logs").insert({
      event: "morning_briefing",
      level: "info",
      message: "Briefing sent successfully",
      metadata: {
        briefingLength: briefing.length,
        rawDataLength: rawData.length
      }
    });
  }
}
main().catch((err) => {
  console.error("Briefing error:", err);
  process.exit(1);
});
